package com.infy.inventrack.inventory.service;
import com.infy.inventrack.common.constants.InfyInvenTrackConstants; import com.infy.inventrack.common.dto.*; import com.infy.inventrack.common.exception.*; import com.infy.inventrack.inventory.client.CatalogClient; import com.infy.inventrack.inventory.entity.InventoryItem; import com.infy.inventrack.inventory.repository.InventoryRepository; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.math.BigDecimal; import java.util.List;
@Service public class InventoryService { private final InventoryRepository repo; private final CatalogClient client; public InventoryService(InventoryRepository r,CatalogClient c){repo=r;client=c;} @Transactional(readOnly=true) @PreAuthorize("hasRole('ADMIN')") public InventoryResponse getStockBySku(String sku,String auth){ validateSku(sku); client.getProduct(sku,auth); InventoryItem i=find(sku); return new InventoryResponse(i.getSku(),i.getStockQuantity(),i.getStockQuantity()<5?"Low Stock":"Available"); } @Transactional @PreAuthorize("hasRole('CUSTOMER')") public String reserveStock(String sku,Integer qty,String auth){ validateSku(sku); if(qty==null||qty<=0) throw invalid("quantity"); client.getProduct(sku,auth); InventoryItem i=find(sku); if(i.getStockQuantity()<qty) return InfyInvenTrackConstants.INSUFFICIENT_STOCK.value(); i.setStockQuantity(i.getStockQuantity()-qty); repo.save(i); return String.format(InfyInvenTrackConstants.STOCK_RESERVED.value(),qty); } @Transactional(readOnly=true) @PreAuthorize("hasRole('ADMIN')") public Double calculateTotalInventoryValue(){ return repo.findAll().stream().map(i->i.getUnitPrice().multiply(BigDecimal.valueOf(i.getStockQuantity()))).reduce(BigDecimal.ZERO,BigDecimal::add).doubleValue(); } @Transactional(readOnly=true) @PreAuthorize("hasRole('ADMIN')") public List<InventoryResponse> findLowStockProducts(Integer t){ if(t==null||t<=0) throw invalid("threshold"); return repo.findAll().stream().filter(i->i.getStockQuantity()<t).map(i->new InventoryResponse(i.getSku(),i.getStockQuantity(),"Low Stock")).toList(); } private InventoryItem find(String sku){return repo.findBySku(sku.trim()).orElseThrow(()->new ResourceNotFoundException(InfyInvenTrackConstants.PRODUCT_NOT_FOUND.value()));} private void validateSku(String sku){ if(sku==null||sku.isBlank()) throw invalid("sku"); } private BusinessValidationException invalid(String a){return new BusinessValidationException(String.format(InfyInvenTrackConstants.INVALID_ATTRIBUTE.value(),a));} }
